package com.recettealarm.app;
import android.content.*;import android.graphics.*;import android.view.*;
public class TimerRingView extends View{Paint bg=new Paint(1),fg=new Paint(1),txt=new Paint(1),sub=new Paint(1);float progress=1f;String time="00:00";public TimerRingView(Context c){super(c);bg.setStyle(Paint.Style.STROKE);fg.setStyle(Paint.Style.STROKE);bg.setStrokeCap(Paint.Cap.ROUND);fg.setStrokeCap(Paint.Cap.ROUND);bg.setStrokeWidth(18);fg.setStrokeWidth(18);bg.setColor(Color.rgb(224,228,222));fg.setColor(UI.lime);txt.setColor(UI.dark);txt.setTextAlign(Paint.Align.CENTER);txt.setTypeface(Typeface.create(Typeface.DEFAULT,Typeface.BOLD));sub.setColor(UI.muted);sub.setTextAlign(Paint.Align.CENTER);}public void setTimer(String t,float p){time=t;progress=Math.max(0,Math.min(1,p));invalidate();}protected void onDraw(Canvas c){super.onDraw(c);int w=getWidth(),h=getHeight();int s=Math.min(w,h)-40;float l=(w-s)/2f,t=(h-s)/2f;RectF r=new RectF(l,t,l+s,t+s);c.drawArc(r,135,270,false,bg);c.drawArc(r,135,270*progress,false,fg);txt.setTextSize(s/5f);c.drawText(time,w/2f,h/2f+10,txt);sub.setTextSize(26);c.drawText("min : sec",w/2f,h/2f+50,sub);} }
